module parallel2serial (
    input wire clk,
    input wire rst_n,
    input wire [3:0]d,
    output wire valid_out,
    output wire dout
);

reg [1:0] cnt;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        cnt <= 2'd0;
    end else begin
        if(cnt == 2'd3) begin
            cnt <= 2'd0;
        end else begin
            cnt <= cnt + 1;
        end
    end
end

reg [3:0] data;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        data <= 4'd0;
    end else begin
        if(cnt == 2'd3) begin
            data <= d;
        end else begin
            data <= {data[2:0], data[3]};
        end
    end
end

reg valid;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        valid <= 1'b0;
    end else begin
        if(cnt == 2'd3) begin
            valid <= 1'b1;
        end else begin
            valid <= 1'b0;
        end
    end
end

assign valid_out = valid;
assign dout = data[3];
endmodule
